us", "secondary_muscles": ["Soleus"], "difficulty": "beginner", "form_cue": "Full range, explosive up, slow down", "substitution": "Single Leg Calf Raises", "exercise_library_id": null, "in_library": false}, {"name": "Hanging Leg Raises", "sets": 3, "reps": 12, "rest_seconds": 30, "weight_guidance": "Bodyweight", "equipment": "Pull-Up Bar", "body_part": "Core", "primary_muscle": "Lower Abs", "secondary_muscles": ["Hip Flexors"], "difficulty": "intermediate", "form_cue": "Control the movement", "substitution": "Lying Leg Raises", "exercise_library_id": null, "in_library": false}]}, {"workout_name": "Day 2 - Lateral Quickness & Defense", "type": "conditioning", "duration_minutes": 45, "exercises": [{"name": "Lateral Shuffle Drill", "sets": 5, "reps": 10, "rest_seconds": 30, "weight_guidance": "10 meters each direction, defensive stance", "equipment": "Cones", "body_part": "Legs", "primary_muscle": "Adductors", "secondary_muscles": ["Glutes", "Quadriceps"], "difficulty": "intermediate", "form_cue": "Stay low, quick feet, don''t cross feet over", "substitution": "Lateral Band Walks", "exercise_library_id": null, "in_library": false}, {"name": "Lateral Bounds", "sets": 4, "reps": 8, "rest_seconds": 45, "weight_guidance": "Maximum lateral distance", "equipment": "None", "body_part": "Legs", "primary_muscle": "Glutes", "secondary_muscles": ["Adductors", "Quadriceps"], "difficulty": "intermediate", "form_cue": "Push off one leg, land softly on other", "substitution": "Skater Jumps", "exercise_library_id": null, "in_library": false}, {"name": "Goblet Lateral Squat", "sets": 3, "reps": 10, "rest_seconds": 45, "weight_guidance": "Moderate dumbbell", "equipment": "Dumbbell", "body_part": "Legs", "primary_muscle": "Adductors", "secondary_muscles": ["Quadriceps", "Glutes"], "difficulty": "intermediate", "form_cue": "Wide stance, shift weight to one side, sit deep", "substitution": "Lateral Lunges", "exercise_library_id": null, "in_library": false}, {"name": "Single Leg Hop (Lateral)", "sets": 3, "reps": 8, "rest_seconds": 45, "weight_guidance": "Hop side to side on one leg", "equipment": "None", "body_part": "Legs", "primary_muscle": "Glutes", "secondary_muscles": ["Calves", "Core"], "difficulty": "intermediate", "form_cue": "Quick hops, stick each landing 1 sec", "substitution": "Skater Jumps", "exercise_library_id": null, "in_library": false}, {"name": "Defensive Slide Sprint Drill", "sets": 5, "reps": 1, "rest_seconds": 45, "weight_guidance": "Slide 5m, sprint 10m, slide 5m", "equipment": "None", "body_part": "Full Body", "primary_muscle": "Quadriceps", "secondary_muscles": ["Adductors", "Calves"], "difficulty": "intermediate", "form_cue": "Low defensive stance, explosive transition to sprint", "substitution": "Shuttle Runs", "exercise_library_id": null, "in_library": false}, {"name": "Copenhagen Plank", "sets": 3, "reps": 20, "rest_seconds": 30, "weight_guidance": "20-second holds each side", "equipment": "Bench", "body_part": "Core", "primary_muscle": "Adductors", "secondary_muscles": ["Obliques"], "difficulty": "intermediate", "form_cue": "Top foot on bench, hold straight line", "substitution": "Side Plank", "exercise_library_id": null, "in_library": false}]}, {"workout_name": "Day 3 - Upper Body & Core Strength", "type": "strength", "duration_minutes": 45, "exercises": [{"name": "Dumbbell Bench Press", "sets": 4, "reps": 8, "rest_seconds": 60, "weight_guidance": "Moderate to heavy", "equipment": "Dumbbells", "body_part": "Chest", "primary_muscle": "Pectoralis Major", "secondary_muscles": ["Triceps", "Anterior Deltoid"], "difficulty": "intermediate", "form_cue": "Control negative, explosive press", "substitution": "Push-Ups", "exercise_library_id": null, "in_library": false}, {"name": "Pull-Ups", "sets": 4, "reps": 8, "rest_seconds": 60, "weight_guidance": "Bodyweight or weighted", "equipment": "Pull-Up Bar", "body_part": "Back", "primary_muscle": "Latissimus Dorsi", "secondary_muscles": ["Biceps", "Rear Deltoids"], "difficulty": "int